{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (preserved via HasDiscriminator config)
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos removed synchronous LINQ APIs (ToList, First, Single, etc.).
        // All queries must use their async counterparts.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

